#!/usr/bin/env bash
set -euo pipefail
TZ="Europe/Prague"
openclaw cron create --name growthlab-morning --agent main --cron "30 6 * * *" --tz "$TZ" --message "[GrowthLab] Proveď ranní research a aktualizuj intel/DAILY-INTEL.md"
