openclaw cron create --name inboxforge-am --agent main --cron "30 7 * * *" --tz "$TZ" --message "[InboxForge] Ranní inbox triage + drafty"
openclaw cron create --name bridge-am-report --agent main --cron "0 8 * * *" --tz "$TZ" --message "[Bridge] Ranní report Josefovi"
openclaw cron create --name growthlab-noon --agent main --cron "0 12 * * *" --tz "$TZ" --message "[GrowthLab] Polední intel update"
openclaw cron create --name dealops-noon --agent main --cron "30 12 * * *" --tz "$TZ" --message "[DealOps] Midday pipeline check"
